import React, { useState } from "react";
import axios from "axios";

function App() {
  const [codeSnippet, setCodeSnippet] = useState(
    `for i in range(len(my_list)):\n    print(my_list[i])`
  );
  const [reviewText, setReviewText] = useState("");
  const [loading, setLoading] = useState(false);
  const [errorMsg, setErrorMsg] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setReviewText("");
    setErrorMsg("");

    try {
      const response = await axios.post(
        "http://localhost:8000/review",
        {
          code: codeSnippet,
          max_length: 128,
          num_beams: 4,
        },
        {
          headers: {
            "Content-Type": "application/json",
          },
        }
      );
      setReviewText(response.data.review);
    } catch (err) {
      console.error(err);
      setErrorMsg(
        err.response?.data?.detail || "An error occurred while calling the API."
      );
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-start p-4 bg-gray-100">
      <h1 className="text-3xl font-bold mb-6 text-gray-700">
        AI‐Powered Code Review Assistant
      </h1>

      <form
        onSubmit={handleSubmit}
        className="w-full max-w-2xl bg-white shadow-md rounded-lg p-6"
      >
        <label htmlFor="code" className="block text-sm font-medium text-gray-600">
          Enter your code snippet:
        </label>
        <textarea
          id="code"
          rows="8"
          className="mt-1 w-full p-2 border border-gray-300 rounded focus:outline-none focus:ring-2 focus:ring-indigo-500"
          value={codeSnippet}
          onChange={(e) => setCodeSnippet(e.target.value)}
        ></textarea>

        <button
          type="submit"
          className="mt-4 px-6 py-2 bg-indigo-600 text-white rounded hover:bg-indigo-700 transition-colors"
          disabled={loading}
        >
          {loading ? "Reviewing…" : "Get Review"}
        </button>
      </form>

      {errorMsg && (
        <div className="mt-4 text-red-600 font-medium">{errorMsg}</div>
      )}

      {reviewText && (
        <div className="mt-6 w-full max-w-2xl bg-white shadow-md rounded-lg p-6">
          <h2 className="text-xl font-semibold text-gray-700 mb-2">Model Output:</h2>
          <pre className="whitespace-pre-wrap text-gray-800">{reviewText}</pre>
        </div>
      )}
    </div>
  );
}

export default App;
